**Key Security Controls**:
- **Cryptographic signature verification**: HMAC-SHA256 proves context came from trusted gateway
- **Timestamp validation**: 30-second window prevents replay attacks
- **Shared secret**: Only gateway and internal services know the signing key
- **Defense in depth**: Multiple checks before trusting any claim

Excellent questions! mTLS provides transport-level trust, but you still need application-level context verification for chained service calls. Here's a production-grade pattern that handles both:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"crypto/tls"
	"crypto/x509"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"
)

// TrustContext carries verified identity through service chain
type TrustContext struct {
	OriginalUserID  string   `json:"original_user_id"`
	OriginalRoles   []string `json:"original_roles"`
	OriginService   string   `json:"origin_service"`
	CallChain       []string `json:"call_chain"`
	MaxHops         int      `json:"max_hops"`
	IssuedAt        int64    `json:"issued_at"`
	ExpiresAt       int64    `json:"expires_at"`
	RequestID       string   `json:"request_id"`
	TrustLevel      string   `json:"trust_level"` // "user", "service", "admin"
}

// TrustBoundaryValidator enforces trust boundaries
type TrustBoundaryValidator struct {
	serviceName       string
	trustedServices   map[string]bool
	signingSecret     []byte
	allowedTrustLevels map[string][]string
	nonceCache        sync.Map
	certPool          *x509.CertPool
}

func NewTrustBoundaryValidator(serviceName string) *TrustBoundaryValidator {
	certPool := x509.NewCertPool()
	caCert, _ := os.ReadFile("/etc/certs/ca.crt")
	certPool.AppendCertsFromPEM(caCert)

	return &TrustBoundaryValidator{
		serviceName:     serviceName,
		signingSecret:   []byte(os.Getenv("SERVICE_MESH_SECRET")),
		trustedServices: loadTrustedServices(),
		allowedTrustLevels: map[string][]string{
			"api-gateway":    {"user", "service", "admin"},
			"auth-service":   {"service", "admin"},
			"order-service":  {"service"},
			"payment-service": {"service"},
		},
		certPool: certPool,
	}
}

func loadTrustedServices() map[string]bool {
	return map[string]bool{
		"api-gateway":     true,
		"auth-service":    true,
		"order-service":   true,
		"payment-service": true,
		"user-service":    true,
	}
}

// ValidateIncomingRequest verifies trust at the boundary
func (v *TrustBoundaryValidator) ValidateIncomingRequest(r *http.Request) (*TrustContext, error) {
	// LAYER 1: mTLS certificate validation
	if r.TLS == nil || len(r.TLS.PeerCertificates) == 0 {
		return nil, fmt.Errorf("mTLS required: no client certificate")
	}

	clientCert := r.TLS.PeerCertificates[0]
	callerService := extractServiceName(clientCert)

	// Verify certificate is from trusted CA and not revoked
	opts := x509.VerifyOptions{
		Roots:     v.certPool,
		KeyUsages: []x509.ExtKeyUsage{x509.ExtKeyUsageClientAuth},
	}
	if _, err := clientCert.Verify(opts); err != nil {
		return nil, fmt.Errorf("certificate verification failed: %w", err)
	}

	// LAYER 2: Service allowlist check
	if !v.trustedServices[callerService] {
		return nil, fmt.Errorf("untrusted service: %s", callerService)
	}

	// LAYER 3: Trust context signature verification
	contextJSON := r.Header.Get("X-Trust-Context")
	signature := r.Header.Get("X-Trust-Signature")

	if !v.verifySignature(contextJSON, signature) {
		return nil, fmt.Errorf("invalid trust context signature")
	}

	var trustCtx TrustContext
	if err := json.Unmarshal([]byte(contextJSON), &trustCtx); err != nil {
		return nil, fmt.Errorf("invalid trust context: %w", err)
	}

	// LAYER 4: Temporal validation
	now := time.Now().Unix()
	if trustCtx.ExpiresAt < now {
		return nil, fmt.Errorf("trust context expired")
	}
	if trustCtx.IssuedAt > now+5 {
		return nil, fmt.Errorf("trust context issued in future")
	}

	// LAYER 5: Chain depth validation (prevent infinite loops)
	if len(trustCtx.CallChain) >= trustCtx.MaxHops {
		return nil, fmt.Errorf("call chain exceeds max hops: %d", trustCtx.MaxHops)
	}

	// LAYER 6: Trust level authorization
	allowedLevels := v.allowedTrustLevels[callerService]
	if !contains(allowedLevels, trustCtx.TrustLevel) {
		return nil, fmt.Errorf("service %s cannot issue trust level %s", 
			callerService, trustCtx.TrustLevel)
	}

	// LAYER 7: Replay prevention
	nonceKey := fmt.Sprintf("%s:%s", trustCtx.RequestID, callerService)
	if _, exists := v.nonceCache.LoadOrStore(nonceKey, time.Now()); exists {
		return nil, fmt.Errorf("replay detected for request %s", trustCtx.RequestID)
	}

	// Update call chain for downstream calls
	trustCtx.CallChain = append(trustCtx.CallChain, v.serviceName)

	log.Printf("[AUDIT] Request validated: user=%s chain=%v trust=%s",
		trustCtx.OriginalUserID, trustCtx.CallChain, trustCtx.TrustLevel)

	return &trustCtx, nil
}

// CreateDownstreamContext creates signed context for calling other services
func (v *TrustBoundaryValidator) CreateDownstreamContext(ctx *TrustContext) (string, string) {
	ctx.CallChain = append(ctx.CallChain, v.serviceName)
	contextJSON, _ := json.Marshal(ctx)
	signature := v.sign(string(contextJSON))
	return string(contextJSON), signature
}

func (v *TrustBoundaryValidator) verifySignature(data, sig string) bool {
	mac := hmac.New(sha256.New, v.signingSecret)
	mac.Write([]byte(data))
	expected := mac.Sum(nil)
	provided, err := base64.StdEncoding.DecodeString(sig)
	if err != nil {
		return false
	}
	return hmac.Equal(expected, provided)
}

func (v *TrustBoundaryValidator) sign(data string) string {
	mac := hmac.New(sha256.New, v.signingSecret)
	mac.Write([]byte(data))
	return base64.StdEncoding.EncodeToString(mac.Sum(nil))
}

func extractServiceName(cert *x509.Certificate) string {
	for _, uri := range cert.URIs {
		if strings.HasPrefix(uri.String(), "spiffe://") {
			parts := strings.Split(uri.Path, "/")
			if len(parts) > 0 {
				return parts[len(parts)-1]
			}
		}
	}
	return cert.Subject.CommonName
}

func contains(slice []string, item string) bool {
	for _, s := range slice {
		if s == item {
			return true
		}
	}
	return false
}

// Secure HTTP client for downstream calls
func createSecureClient(validator *TrustBoundaryValidator) *http.Client {
	cert, _ := tls.LoadX509KeyPair(
		"/etc/certs/service.crt",
		"/etc/certs/service.key",
	)

	tlsConfig := &tls.Config{
		Certificates: []tls.Certificate{cert},
		RootCAs:      validator.certPool,
		MinVersion:   tls.VersionTLS13,
	}

	return &http.Client{
		Timeout: 30 * time.Second,
		Transport: &http.Transport{
			TLSClientConfig: tlsConfig,
		},
	}
}

func main() {
	validator := NewTrustBoundaryValidator("order-service")

	http.HandleFunc("/api/orders", func(w http.ResponseWriter, r *http.Request) {
		trustCtx, err := validator.ValidateIncomingRequest(r)
		if err != nil {
			log.Printf("[SECURITY] Trust boundary violation: %v", err)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Safe to proceed with validated context
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]interface{}{
			"status":  "success",
			"user_id": trustCtx.OriginalUserID,
			"chain":   trustCtx.CallChain,
		})
	})

	// Configure mTLS server
	cert, _ := tls.LoadX509KeyPair("/etc/certs/service.crt", "/etc/certs/service.key")
	tlsConfig := &tls.Config{
		Certificates: []tls.Certificate{cert},
		ClientCAs:    validator.certPool,
		ClientAuth:   tls.RequireAndVerifyClientCert,
		MinVersion:   tls.VersionTLS13,
	}

	server := &http.Server{
		Addr:      ":8443",
		TLSConfig: tlsConfig,
	}

	log.Println("Starting secure service with mTLS...")
	log.Fatal(server.ListenAndServeTLS("", ""))
}
```

**Defense in Depth Layers**:

1. **mTLS Certificate Validation**: Transport-level identity verification using X.509 certificates with SPIFFE URIs for service identity

2. **Service Allowlist**: Only explicitly trusted services can communicate, even with valid certificates

3. **Cryptographic Context Signing**: HMAC-SHA256 ensures context integrity and authenticity

4. **Temporal Controls**: Issue time and expiration prevent replay of old contexts

5. **Chain Depth Limits**: MaxHops prevents infinite loops and limits blast radius

6. **Trust Level Authorization**: Services can only propagate trust levels they're authorized for

7. **Replay Prevention**: Nonce cache prevents reuse of request IDs

**Additional Protections**:

- **SPIFFE/SPIRE integration**: Use SPIFFE IDs in certificates for workload identity
- **Network policies**: Kubernetes NetworkPolicy or service mesh to restrict communication paths
- **Audit logging**: Every trust boundary crossing is logged with full context for forensics
- **Certificate rotation**: Short-lived certificates (24h) limit exposure from compromised keys
- **Circuit breakers**: Prevent cascading failures when downstream services are compromised
- **Rate limiting per service**: Prevent one compromised service from overwhelming others

This is a critical trust boundary violation risk. Many organizations assume internal network traffic is inherently trustworthy, but this assumption has led to devastating breaches including the 2023 Retool incident where attackers leveraged compromised internal credentials to access customer systems.

**VULNERABLE CODE**:

```javascript
