  'user-service': {
    publicKey: process.env.USER_SERVICE_PUBLIC_KEY,
    allowedEndpoints: ['/api/admin/users/*'],
    allowedActions: ['read']
  },
  'billing-service': {
    publicKey: process.env.BILLING_SERVICE_PUBLIC_KEY,
    allowedEndpoints: ['/api/internal/customer-data'],
    allowedActions: ['read', 'update_billing']
  }
