const verifyServiceIdentity = async (req, res, next) => {
  const serviceToken = req.headers['x-service-token'];
  const serviceId = req.headers['x-service-id'];

  if (!serviceToken || !serviceId) {
    req.verifiedService = null;
    return next();
  }

  const service = SERVICE_REGISTRY[serviceId];
  if (!service) {
    console.warn(`Unknown service attempted access: ${serviceId}`);
    return res.status(401).json({ error: 'Unknown service' });
  }

  try {
    // Verify JWT signature with service's public key
    const decoded = jwt.verify(serviceToken, service.publicKey, {
      algorithms: ['RS256'],
      issuer: serviceId,
      audience: 'internal-api'
    });

    // Verify request is within allowed scope
    const requestPath = req.path;
    const isAllowedEndpoint = service.allowedEndpoints.some(pattern => {
      const regex = new RegExp('^' + pattern.replace('*', '.*') + '$');
      return regex.test(requestPath);
    });

    if (!isAllowedEndpoint) {
      console.warn(`Service ${serviceId} attempted unauthorized endpoint: ${requestPath}`);
      return res.status(403).json({ error: 'Endpoint not authorized for this service' });
    }

    req.verifiedService = {
      id: serviceId,
      allowedActions: service.allowedActions,
      requestId: decoded.requestId,
      timestamp: decoded.iat
    };

  } catch (err) {
    console.error(`Service token verification failed: ${err.message}`);
    return res.status(401).json({ error: 'Invalid service token' });
  }

  next();
};

