**Key Security Controls**:
- **Cryptographic service identity**: JWT signed with private keys, verified with public keys from trusted registry
- **Explicit endpoint authorization**: Services can only access pre-defined endpoints
- **Action-level permissions**: Even verified services have limited actions they can perform
- **Comprehensive audit logging**: All service-to-service requests logged with correlation IDs

This is exactly where most trust boundary violations occur - at the transition points between security zones. The 2023 Retool breach specifically exploited the assumption that once data entered the 'internal' zone, it could be trusted. Production systems need explicit trust boundary enforcement at every transition.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Joi = require('joi');
const crypto = require('crypto');
const { createLogger, transports, format } = require('winston');

// Security zone definitions
const SECURITY_ZONES = {
  EXTERNAL: { level: 0, name: 'external', trustLevel: 'untrusted' },
  DMZ: { level: 1, name: 'dmz', trustLevel: 'partially_trusted' },
  INTERNAL: { level: 2, name: 'internal', trustLevel: 'verified' },
  PRIVILEGED: { level: 3, name: 'privileged', trustLevel: 'highly_verified' }
};

// Audit logger for trust boundary crossings
const securityLogger = createLogger({
  level: 'info',
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  transports: [
    new transports.File({ filename: 'trust-boundary-audit.log' }),
    new transports.Console()
  ]
});

// Trust boundary context that tracks data lineage
class TrustBoundaryContext {
  constructor(sourceZone, data, originalSource) {
    this.id = crypto.randomUUID();
    this.sourceZone = sourceZone;
    this.currentZone = sourceZone;
    this.data = data;
    this.originalSource = originalSource;
    this.validations = [];
    this.transformations = [];
    this.createdAt = new Date().toISOString();
  }

  recordValidation(validationType, passed, details) {
    this.validations.push({
      type: validationType,
      passed,
      details,
      timestamp: new Date().toISOString()
    });
  }

  recordTransformation(transformationType, details) {
    this.transformations.push({
      type: transformationType,
      details,
      timestamp: new Date().toISOString()
    });
  }

  canTransitionTo(targetZone) {
    // Higher trust zones require explicit validation
    if (targetZone.level > this.currentZone.level) {
      const requiredValidations = targetZone.level - this.currentZone.level;
      const passedValidations = this.validations.filter(v => v.passed).length;
      return passedValidations >= requiredValidations;
    }
    return true;
  }

  transitionTo(targetZone) {
    if (!this.canTransitionTo(targetZone)) {
      throw new TrustBoundaryViolationError(
        `Cannot transition from ${this.currentZone.name} to ${targetZone.name}`,
        this
      );
    }

    securityLogger.info({
      event: 'trust_boundary_transition',
      contextId: this.id,
      fromZone: this.currentZone.name,
      toZone: targetZone.name,
      validationsApplied: this.validations.length,
      originalSource: this.originalSource
    });

    this.currentZone = targetZone;
    return this;
  }
}

class TrustBoundaryViolationError extends Error {
  constructor(message, context) {
    super(message);
    this.name = 'TrustBoundaryViolationError';
    this.context = context;
  }
}

// Validation schemas for each trust level transition
const validationSchemas = {
  externalToDmz: Joi.object({
    customerId: Joi.string().uuid().required(),
    action: Joi.string().valid('read', 'update', 'delete').required(),
    data: Joi.object().unknown(true)
  }),

  dmzToInternal: Joi.object({
    customerId: Joi.string().uuid().required(),
    action: Joi.string().valid('read', 'update').required(),
    data: Joi.object({
      // More restrictive - no dangerous fields
      name: Joi.string().max(100).pattern(/^[a-zA-Z0-9\s]+$/),
      email: Joi.string().email(),
      preferences: Joi.object().unknown(false)
    })
  }),

  internalToPrivileged: Joi.object({
    customerId: Joi.string().uuid().required(),
    action: Joi.string().valid('read').required(),
    approvalToken: Joi.string().required(),
    justification: Joi.string().min(20).required()
  })
};

// Trust boundary gateway middleware
const createTrustBoundaryGateway = (sourceZone, targetZone, schema) => {
  return async (req, res, next) => {
    const context = req.trustContext || new TrustBoundaryContext(
      sourceZone,
      req.body,
      {
        ip: req.ip,
        userAgent: req.headers['user-agent'],
        timestamp: new Date().toISOString()
      }
    );

    try {
      // Step 1: Schema validation
      const { error, value } = schema.validate(req.body, { stripUnknown: true });

      if (error) {
        context.recordValidation('schema', false, error.details);
        securityLogger.warn({
          event: 'trust_boundary_validation_failed',
          contextId: context.id,
          validationType: 'schema',
          error: error.details,
          sourceZone: sourceZone.name,
          targetZone: targetZone.name
        });
        return res.status(400).json({ error: 'Validation failed', details: error.details });
      }

      context.recordValidation('schema', true, { fieldsValidated: Object.keys(value) });

      // Step 2: Sanitize and transform data
      const sanitizedData = sanitizeForZone(value, targetZone);
      context.recordTransformation('sanitization', { targetZone: targetZone.name });

      // Step 3: Additional security checks for higher trust zones
      if (targetZone.level >= SECURITY_ZONES.PRIVILEGED.level) {
        const approvalValid = await verifyApprovalToken(value.approvalToken, value.customerId);
        context.recordValidation('approval_token', approvalValid, {});

        if (!approvalValid) {
          securityLogger.error({
            event: 'privileged_access_denied',
            contextId: context.id,
            customerId: value.customerId,
            reason: 'Invalid approval token'
          });
          return res.status(403).json({ error: 'Privileged access requires valid approval' });
        }
      }

      // Step 4: Attempt zone transition
      context.data = sanitizedData;
      context.transitionTo(targetZone);

      req.trustContext = context;
      req.body = sanitizedData;
      next();

    } catch (err) {
      if (err instanceof TrustBoundaryViolationError) {
        securityLogger.error({
          event: 'trust_boundary_violation',
          contextId: context.id,
          error: err.message,
          context: {
            sourceZone: context.sourceZone.name,
            currentZone: context.currentZone.name,
            validations: context.validations
          }
        });
        return res.status(403).json({ error: 'Trust boundary violation' });
      }
      throw err;
    }
  };
};

// Sanitization for each security zone
function sanitizeForZone(data, targetZone) {
  const sanitized = JSON.parse(JSON.stringify(data));

  // Remove fields that shouldn't cross into higher trust zones
  if (targetZone.level >= SECURITY_ZONES.INTERNAL.level) {
    delete sanitized.__proto__;
    delete sanitized.constructor;

    // Recursive sanitization of nested objects
    Object.keys(sanitized).forEach(key => {
      if (typeof sanitized[key] === 'string') {
        // Remove potential injection patterns
        sanitized[key] = sanitized[key]
          .replace(/[<>"'&]/g, '')
          .substring(0, 1000);
      }
    });
  }

  return sanitized;
}

async function verifyApprovalToken(token, customerId) {
  // In production: verify against approval service
  // Check token signature, expiry, and scope
  try {
    const decoded = jwt.verify(token, process.env.APPROVAL_PUBLIC_KEY);
    return decoded.customerId === customerId && decoded.exp > Date.now() / 1000;
  } catch {
    return false;
  }
}

// Application routes with trust boundary enforcement
const app = express();
app.use(express.json());

// External -> DMZ: Initial customer data submission
app.post('/api/customer/submit',
  createTrustBoundaryGateway(
    SECURITY_ZONES.EXTERNAL,
    SECURITY_ZONES.DMZ,
    validationSchemas.externalToDmz
  ),
  async (req, res) => {
    // Data is now in DMZ trust level
    const result = await processDmzRequest(req.body, req.trustContext);
    res.json(result);
  }
);

// DMZ -> Internal: Process validated customer data
app.post('/api/internal/process',
  createTrustBoundaryGateway(
    SECURITY_ZONES.DMZ,
    SECURITY_ZONES.INTERNAL,
    validationSchemas.dmzToInternal
  ),
  async (req, res) => {
    // Data has been re-validated for internal processing
    const result = await processInternalRequest(req.body, req.trustContext);
    res.json(result);
  }
);

// Internal -> Privileged: Access sensitive operations
app.post('/api/privileged/sensitive-action',
  createTrustBoundaryGateway(
    SECURITY_ZONES.INTERNAL,
    SECURITY_ZONES.PRIVILEGED,
    validationSchemas.internalToPrivileged
  ),
  async (req, res) => {
    // Requires approval token and justification
    securityLogger.info({
      event: 'privileged_action_executed',
      contextId: req.trustContext.id,
      action: req.body.action,
      justification: req.body.justification
    });

    const result = await executePrivilegedAction(req.body, req.trustContext);
    res.json(result);
  }
);

// Global error handler for trust boundary violations
app.use((err, req, res, next) => {
  if (err instanceof TrustBoundaryViolationError) {
    return res.status(403).json({
      error: 'Security violation',
      message: 'Request blocked by trust boundary controls'
    });
  }
  next(err);
});

module.exports = { app, TrustBoundaryContext, SECURITY_ZONES };
```

