import javax.servlet.http.*;
import java.io.*;
import java.sql.*;
import java.util.regex.Pattern;
import com.fasterxml.jackson.databind.ObjectMapper;
import io.jsonwebtoken.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureOrderProcessingService extends HttpServlet {
    private static final Logger auditLog = LoggerFactory.getLogger("AUDIT");
    private static final ObjectMapper mapper = new ObjectMapper();
    private static final Pattern PRODUCT_ID_PATTERN = Pattern.compile("^[A-Z0-9]{8,12}$");
    private final JwtValidator jwtValidator;
    private final DataSource dataSource;

    public SecureOrderProcessingService(JwtValidator jwtValidator, DataSource dataSource) {
        this.jwtValidator = jwtValidator;
        this.dataSource = dataSource;
    }

    @Override
    protected void doPost(HttpServletRequest request,
                          HttpServletResponse response) throws IOException {

        // SECURITY CONTROL 1: Verify service identity with mTLS certificate
        String clientCertDN = (String) request.getAttribute(
            "javax.servlet.request.X509Certificate");
        if (!isAuthorizedService(clientCertDN)) {
            auditLog.warn("Unauthorized service attempt: {}", clientCertDN);
            response.sendError(403, "Service not authorized");
            return;
        }

        // SECURITY CONTROL 2: Validate service-to-service JWT token
        String serviceToken = request.getHeader("X-Service-Token");
        ServiceContext serviceCtx = jwtValidator.validateServiceToken(serviceToken);
        if (serviceCtx == null || !serviceCtx.hasPermission("order:process")) {
            auditLog.warn("Invalid service token from: {}", clientCertDN);
            response.sendError(401, "Invalid service credentials");
            return;
        }

        // SECURITY CONTROL 3: Re-validate ALL input at trust boundary
        OrderRequest order = mapper.readValue(
            request.getInputStream(), 
            OrderRequest.class
        );

        ValidationResult validation = validateOrderAtBoundary(order);
        if (!validation.isValid()) {
            auditLog.warn("Validation failed at boundary: {}", validation.getErrors());
            response.sendError(400, "Invalid order data");
            return;
        }

        // SECURITY CONTROL 4: Use parameterized queries with least privilege
        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            String sql = "UPDATE inventory SET quantity = quantity - ? " +
                        "WHERE product_id = ? AND quantity >= ?";
            try (PreparedStatement stmt = conn.prepareStatement(sql)) {
                stmt.setInt(1, order.getQuantity());
                stmt.setString(2, order.getProductId());
                stmt.setInt(3, order.getQuantity());

                int updated = stmt.executeUpdate();
                if (updated == 0) {
                    conn.rollback();
                    response.sendError(409, "Insufficient inventory");
                    return;
                }
            }

            // SECURITY CONTROL 5: Re-authenticate user for payment
            forwardToPaymentServiceSecurely(order, serviceCtx);

            conn.commit();
            auditLog.info("Order processed: productId={}, quantity={}, service={}",
                order.getProductId(), order.getQuantity(), serviceCtx.getServiceId());
        } catch (SQLException e) {
            auditLog.error("Database error processing order", e);
            response.sendError(500, "Processing error");
        }
    }

    private ValidationResult validateOrderAtBoundary(OrderRequest order) {
        ValidationResult result = new ValidationResult();

        // Re-validate even "trusted" internal data
        if (order.getProductId() == null || 
            !PRODUCT_ID_PATTERN.matcher(order.getProductId()).matches()) {
            result.addError("Invalid product ID format");
        }

        if (order.getQuantity() <= 0 || order.getQuantity() > 1000) {
            result.addError("Quantity must be between 1 and 1000");
        }

        if (order.getAmount() <= 0 || order.getAmount() > 100000) {
            result.addError("Amount out of acceptable range");
        }

        return result;
    }

    private boolean isAuthorizedService(String certDN) {
        // Verify against allowlist of service certificates
        return certDN != null && 
               certDN.contains("OU=InternalServices") &&
               certDN.contains("CN=inventory-service");
    }
}
